    function drawJelly(x,y,r,phase){const pulse=0.85+0.15*Math.sin(phase);ctx.save();ctx.translate(x,y);const jg=ctx.createRadialGradient(0,-r*0.2,0,0,0,r*pulse);jg.addColorStop(0,'rgba(180,120,255,0.38)');jg.addColorStop(0.5,'rgba(140,80,240,0.22)');jg.addColorStop(1,'rgba(100,40,200,0.05)');ctx.fillStyle=jg;ctx.beginPath();ctx.arc(0,0,r*pulse,Math.PI,0);ctx.fill();ctx.strokeStyle='rgba(200,150,255,0.45)';ctx.lineWidth=1.5;ctx.beginPath();ctx.arc(0,0,r*pulse,Math.PI,0);ctx.stroke();ctx.strokeStyle='rgba(180,120,255,0.30)';ctx.lineWidth=1.0;for(let ti=-3;ti<=3;ti++){const tx=ti*(r*0.22);const tlen=r*(1.2+0.4*Math.sin(phase+ti));ctx.beginPath();ctx.moveTo(tx,0);ctx.bezierCurveTo(tx+Math.sin(phase+ti)*8,tlen*0.4,tx-Math.sin(phase+ti*0.7)*6,tlen*0.75,tx+Math.sin(phase*1.3+ti)*5,tlen);ctx.stroke();}ctx.restore();}
