     const og=ctx.createLinearGradient(0,0,0,H);og.addColorStop(0,'rgba(0,80,160,0.07)');og.addColorStop(1,'rgba(0,20,60,0.10)');ctx.fillStyle=og;ctx.fillRect(0,0,W,H);
     for(let i=0;i<4;i++){const bx=W*(0.15+i*0.25)+Math.sin(t*0.3+i)*20;const bg=ctx.createLinearGradient(bx,0,bx+40,H);bg.addColorStop(0,`rgba(100,180,255,${0.05+Math.sin(t*0.4+i)*0.02})`);bg.addColorStop(1,'rgba(0,40,120,0)');ctx.fillStyle=bg;ctx.beginPath();ctx.moveTo(bx,0);ctx.lineTo(bx+15,0);ctx.lineTo(bx+80,H);ctx.lineTo(bx-40,H);ctx.closePath();ctx.fill();}
