     for(const d of deepfish){d.x+=d.vx;d.phase+=0.018;if(d.x>W+d.size*2)d.x=-d.size*2;if(d.x<-d.size*2)d.x=W+d.size*2;ctx.save();ctx.translate(d.x,d.y+Math.sin(d.phase)*4);if(d.vx>0)ctx.scale(-1,1);ctx.fillStyle='rgba(5,20,60,0.55)';ctx.beginPath();ctx.ellipse(0,0,d.size,d.size*0.48,0,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.moveTo(-d.size,0);ctx.lineTo(-d.size*1.5,-d.size*0.45);ctx.lineTo(-d.size*1.5,d.size*0.45);ctx.closePath();ctx.fill();ctx.restore();}
