     for(const f of clownfish){f.x+=f.vx;f.y+=f.vy+Math.sin(t*0.5+f.phase)*0.25;f.tailPh+=0.16;if(f.x>W+f.size*2)f.x=-f.size*2;if(f.x<-f.size*2)f.x=W+f.size*2;if(f.y<H*0.05)f.vy=Math.abs(f.vy)*0.8;if(f.y>H*0.90)f.vy=-Math.abs(f.vy)*0.8;drawClownFish(f.x,f.y,f.size,f.vx<0,f.tailPh);}
     const vg=ctx.createRadialGradient(W/2,H/2,H*0.1,W/2,H/2,H*0.8);vg.addColorStop(0,'rgba(0,0,0,0)');vg.addColorStop(1,'rgba(0,10,40,0.65)');ctx.fillStyle=vg;ctx.fillRect(0,0,W,H);
