    _llPos.textContent='#splash-content-wrap{top:20%!important;transform:translateY(0)!important;}#splash-content-wrap.reveal{transform:translateY(0)!important;}';
    const _llWatch=setInterval(()=>{if(stop.v){_llPos.textContent='';clearInterval(_llWatch);}},200);

    /* ── Pride Rock SVG — Path2D depuis le fichier fourni ── */
    const PR_W=366.11, PR_H=271.02;
    const _prBase  =new Path2D('M0 269.85 73.2 270.98 72.86 251.17 83.1 236.15 115 245.13 83.98 268.58 81.25 270.31 366.11 271.02 360.19 259.06 327.97 229.45 299.73 199.19 274.73 170.19 241.73 117.19 232.73 110.19 215.73 85.19 204.73 78.19 195.73 65.19 185.73 49.19 182.73 48.19 159.73 5.19 145.92 0.2 134.93 9.8 134.63 20.59 131.88 23.22 136.47 115.18 133.64 120.5 137.31 213.34 28.13 189.6 18.16 194.72 18.09 197.42 21.56 201.12 39.13 211.51 39.92 215.14 45.23 217.09 46.02 220.71 63.64 229.3 26.18 259.77 17.28 258.63 0 269.85Z');
